+        let commits = vec![make_commit(1, 1, &[]), make_commit(2, 2, &[])];
+        let results = w.append_commits_coalesced(&commits).unwrap();
+
+        assert_eq!(results.len(), 2);
+        assert!(results.iter().all(|result| !result.synced));
+        assert!(
+            results
